1	import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
2	import { useEffect, useState } from 'react';
3	import { RouterProvider } from 'react-router-dom';
4	import { Toaster } from 'sonner';
5	import { router } from './router';
6	import { getMe } from '@/features/auth/authApi';
7	import { useAuthStore } from '@/store/useAuthStore';
8	import { useThemeStore } from '@/store/useThemeStore';
9	
10	const ThemeBootstrap = () => {
11	    const apply = useThemeStore((state) => state.apply);
12	    useEffect(() => {
13	        apply();
14	    }, [apply]);
15	    return null;
16	};
17	
18	const AuthBootstrap = () => {
19	    const setUser = useAuthStore((state) => state.setUser);
20	    const logout = useAuthStore((state) => state.logout);
21	    const markAuthResolved = useAuthStore((state) => state.markAuthResolved);
22	    const resetAuthResolution = useAuthStore((state) => state.resetAuthResolution);
23	
24	    useEffect(() => {
25	        if (window.location.pathname === '/login') {
26	            markAuthResolved();
27	            return;
28	        }
29	
30	        let cancelled = false;
31	        resetAuthResolution();
32	
33	        getMe()
34	            .then((user) => {
35	                if (!cancelled) {
36	                    setUser(user);
37	                }
38	            })
39	            .catch(() => {
40	                if (!cancelled) {
41	                    logout();
42	                }
43	            });
44	
45	        return () => {
46	            cancelled = true;
47	        };
48	    }, [logout, markAuthResolved, resetAuthResolution, setUser]);
49	
50	    return null;
51	};
52	
53	export const Providers = () => {
54	    const [queryClient] = useState(
55	        () =>
56	            new QueryClient({
57	                defaultOptions: {
58	                    queries: {
59	                        retry: 1,
60	                        staleTime: 1000 * 60 * 5,
61	                    },
62	                },
63	            }),
64	    );
65	
66	    return (
67	        <QueryClientProvider client={queryClient}>
68	            <ThemeBootstrap />
69	            <AuthBootstrap />
70	            <RouterProvider router={router} />
71	            <Toaster richColors position="top-right" />
72	        </QueryClientProvider>
73	    );
74	}
