1	import { create } from 'zustand';
2	import { persist } from 'zustand/middleware';
3	
4	export const useThemeStore = create(
5	    persist(
6	        (set, get) => ({
7	            theme: 'light',
8	            toggle: () => {
9	                const next = get().theme === 'light' ? 'dark' : 'light';
10	                document.documentElement.classList.toggle('dark', next === 'dark');
11	                set({ theme: next });
12	            },
13	            apply: () => {
14	                document.documentElement.classList.toggle('dark', get().theme === 'dark');
15	            },
16	        }),
17	        { name: 'trmdict-theme' }
18	    )
19	);
