1	import { Navigate, useLocation } from 'react-router-dom';
2	import { useAuthStore } from '@/store/useAuthStore';
3	
4	export const ProtectedRoute = ({ children }) => {
5	    const isAuthenticated = useAuthStore((state) => state.isAuthenticated);
6	    const authResolved = useAuthStore((state) => state.authResolved);
7	    const location = useLocation();
8	
9	    if (!authResolved) {
10	        return null;
11	    }
12	
13	    if (!isAuthenticated) {
14	        return <Navigate to={`/login?returnUrl=${encodeURIComponent(location.pathname)}`} replace />;
15	    }
16	
17	    return children;
18	};
