1	import { zodResolver } from '@hookform/resolvers/zod';
2	import { useMutation } from '@tanstack/react-query';
3	import { useForm } from 'react-hook-form';
4	import { useNavigate, useSearchParams } from 'react-router-dom';
5	import { Button } from '@/shared/components/ui/button';
6	import { Input } from '@/shared/components/ui/input';
7	import { useAuthStore } from '@/store/useAuthStore';
8	import { login } from './authApi';
9	import { loginSchema } from './login.schema';
10	
11	const getSafeReturnUrl = (rawReturnUrl) => {
12	    if (typeof rawReturnUrl !== 'string') {
13	        return '/home';
14	    }
15	
16	    if (!rawReturnUrl.startsWith('/') || rawReturnUrl.startsWith('//')) {
17	        return '/home';
18	    }
19	
20	    return rawReturnUrl;
21	};
22	
23	export const LoginPage = () => {
24	    const navigate = useNavigate();
25	    const [searchParams] = useSearchParams();
26	    const setUser = useAuthStore((state) => state.setUser);
27	    const returnUrl = getSafeReturnUrl(searchParams.get('returnUrl') || '/home');
28	    const {
29	        register,
30	        handleSubmit,
31	        formState: { errors },
32	    } = useForm({
33	        resolver: zodResolver(loginSchema),
34	        defaultValues: {
35	            username: '',
36	            password: '',
37	        },
38	    });
39	
40	    const mutation = useMutation({
41	        mutationFn: login,
42	        onSuccess: (data) => {
43	            setUser(data.user);
44	            navigate(returnUrl, { replace: true });
45	        },
46	    });
47	
48	    const usernameErrorId = errors.username ? 'login-username-error' : undefined;
49	    const passwordErrorId = errors.password ? 'login-password-error' : undefined;
50	    const mutationErrorId = mutation.isError ? 'login-form-error' : undefined;
51	    const mutationErrorMessage =
52	        mutation.error instanceof Error && mutation.error.message
53	            ? mutation.error.message
54	            : '로그인에 실패했습니다.';
55	
56	    return (
57	        <section className='w-full max-w-sm rounded-2xl border border-slate-200 bg-white p-8 shadow-xl shadow-slate-200/60 dark:border-slate-800 dark:bg-slate-950 dark:shadow-none'>
58	            <header className='mb-6 space-y-2'>
59	                <div className='mb-4 flex h-10 w-10 items-center justify-center rounded-xl bg-gradient-to-br from-blue-600 to-blue-400 text-base font-bold text-white shadow-sm'>
60	                    T
61	                </div>
62	                <h1 className='text-2xl font-semibold text-slate-900 dark:text-slate-100'>TrmWordDict</h1>
63	                <p className='text-sm text-slate-500 dark:text-slate-400'>단정한 용어 사전 시스템</p>
64	            </header>
65	            <form className='space-y-4' onSubmit={handleSubmit((values) => mutation.mutate(values))}>
66	                <div className='space-y-2'>
67	                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='username'>
68	                        아이디
69	                    </label>
70	                    <Input
71	                        id='username'
72	                        aria-describedby={usernameErrorId}
73	                        aria-invalid={errors.username ? 'true' : undefined}
74	                        autoComplete='username'
75	                        {...register('username')}
76	                    />
77	                    {errors.username ? (
78	                        <p
79	                            id={usernameErrorId}
80	                            role='alert'
81	                            className='text-sm text-rose-600 dark:text-rose-400'
82	                        >
83	                            {errors.username.message}
84	                        </p>
85	                    ) : null}
86	                </div>
87	                <div className='space-y-2'>
88	                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='password'>
89	                        비밀번호
90	                    </label>
91	                    <Input
92	                        id='password'
93	                        aria-describedby={passwordErrorId}
94	                        aria-invalid={errors.password ? 'true' : undefined}
95	                        autoComplete='current-password'
96	                        type='password'
97	                        {...register('password')}
98	                    />
99	                    {errors.password ? (
100	                        <p
101	                            id={passwordErrorId}
102	                            role='alert'
103	                            className='text-sm text-rose-600 dark:text-rose-400'
104	                        >
105	                            {errors.password.message}
106	                        </p>
107	                    ) : null}
108	                </div>
109	                {mutation.isError ? (
110	                    <p id={mutationErrorId} role='alert' className='text-sm text-rose-600 dark:text-rose-400'>
111	                        {mutationErrorMessage}
112	                    </p>
113	                ) : null}
114	                <Button className='w-full' type='submit' disabled={mutation.isPending}>
115	                    로그인
116	                </Button>
117	            </form>
118	        </section>
119	    );
120	};
