1	import { useState } from 'react';
2	import { useQuery } from '@tanstack/react-query';
3	import { DataGrid } from '@/shared/components/DataGrid/DataGrid';
4	import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
5	import { Input } from '@/shared/components/ui/input';
6	import { emptyToNull, requestJson, toSnakeCase } from '@/shared/query/queryHelpers';
7	import { DomainDetailDialog } from './DomainDetailDialog';
8	
9	const dataTypeOptions = ['', 'VARCHAR', 'CHAR', 'NUMERIC', 'DATETIME'];
10	
11	const columns = [
12	    { key: 'stdDmnNm', header: '도메인명', sortable: true, width: 220 },
13	    { key: 'stdDmnGroupNm', header: '그룹명', sortable: true, width: 140 },
14	    { key: 'stdDmnClsfNm', header: '분류명', sortable: true, width: 140 },
15	    { key: 'dataTypeNm', header: '데이터타입', sortable: true, width: 110 },
16	    { key: 'dataLen', header: '길이', sortable: false, width: 80, align: 'end' },
