18	    { key: 'enctCycl', header: '제정차수', sortable: false, width: 140 },
19	    { key: 'useYn', header: '사용', sortable: false, width: 70, align: 'center' },
20	];
21	
22	const initialFilters = {
23	    stdDmnNm: '',
24	    stdDmnGroupNm: '',
25	    stdDmnClsfNm: '',
26	    dataTypeNm: '',
27	    useYn: '',
28	};
29	
30	export const DomainListPage = () => {
31	    const [filters, setFilters] = useState(initialFilters);
32	    const [request, setRequest] = useState({ page: 1, size: 20 });
33	    const [selectedId, setSelectedId] = useState(null);
34	    const pageQuery = useQuery({
35	        queryKey: ['domain-list', request],
36	        queryFn: ({ signal }) =>
37	            requestJson({
38	                method: 'post',
39	                url: '/domains/search',
40	                data: request,
41	                signal,
42	            }),
43	    });
44	
45	    const selectedDomainQuery = useQuery({
46	        queryKey: ['domain-detail', selectedId],
47	        queryFn: ({ signal }) =>
48	            requestJson({
49	                method: 'get',
50	                url: `/domains/${selectedId}`,
51	                signal,
52	            }),
53	        enabled: selectedId !== null && selectedId !== undefined,
54	        staleTime: 5 * 60 * 1000,
55	    });
56	
57	    return (
58	        <div className='space-y-6'>
59	            <SearchForm
60	                onSubmit={() => {
61	                    setRequest({
62	                        page: 1,
63	                        size: request.size,
64	                        stdDmnNm: emptyToNull(filters.stdDmnNm),
