75	            >
76	                <div className='grid w-full gap-3 md:grid-cols-2 xl:grid-cols-5'>
77	                    <div className='space-y-2'>
78	                        <label className='text-sm font-medium text-foreground' htmlFor='stdDmnNm'>
79	                            도메인명
80	                        </label>
81	                        <Input
82	                            id='stdDmnNm'
83	                            value={filters.stdDmnNm}
84	                            onChange={(event) => setFilters((current) => ({ ...current, stdDmnNm: event.target.value }))}
85	                        />
86	                    </div>
87	                    <div className='space-y-2'>
88	                        <label className='text-sm font-medium text-foreground' htmlFor='stdDmnGroupNm'>
89	                            그룹명
90	                        </label>
91	                        <Input
92	                            id='stdDmnGroupNm'
93	                            value={filters.stdDmnGroupNm}
94	                            onChange={(event) =>
95	                                setFilters((current) => ({ ...current, stdDmnGroupNm: event.target.value }))
96	                            }
97	                        />
98	                    </div>
99	                    <div className='space-y-2'>
100	                        <label className='text-sm font-medium text-foreground' htmlFor='stdDmnClsfNm'>
101	                            분류명
102	                        </label>
103	                        <Input
104	                            id='stdDmnClsfNm'
105	                            value={filters.stdDmnClsfNm}
106	                            onChange={(event) =>
107	                                setFilters((current) => ({ ...current, stdDmnClsfNm: event.target.value }))
108	                            }
109	                        />
110	                    </div>
111	                    <div className='space-y-2'>
112	                        <label className='text-sm font-medium text-foreground' htmlFor='dataTypeNm'>
113	                            데이터타입
114	                        </label>
115	                        <select
116	                            id='dataTypeNm'
117	                            className='flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm text-foreground'
118	                            value={filters.dataTypeNm}
119	                            onChange={(event) => setFilters((current) => ({ ...current, dataTypeNm: event.target.value }))}
120	                        >
121	                            {dataTypeOptions.map((option) => (
122	                                <option key={option || 'all'} value={option}>
123	                                    {option || '전체'}
124	                                </option>
125	                            ))}
126	                        </select>
127	                    </div>
128	                    <div className='space-y-2'>
129	                        <label className='text-sm font-medium text-foreground' htmlFor='useYn'>
130	                            사용여부
131	                        </label>
132	                        <select
133	                            id='useYn'
134	                            className='flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm text-foreground'
135	                            value={filters.useYn}
136	                            onChange={(event) => setFilters((current) => ({ ...current, useYn: event.target.value }))}
137	                        >
138	                            <option value=''>전체</option>
139	                            <option value='Y'>사용</option>
140	                            <option value='N'>미사용</option>
141	                        </select>
142	                    </div>
143	                </div>
144	            </SearchForm>
145	
146	            <DataGrid
