74	
75	    if (totalPages <= 7) {
76	        return Array.from({ length: totalPages }, (_, index) => ({ type: 'page', value: index + 1 }));
77	    }
78	
79	    const pages = new Set([1, totalPages, currentPage - 1, currentPage, currentPage + 1]);
80	    const ordered = [...pages]
