1	import { Link, useLocation, useMatches } from 'react-router-dom';
2	
3	const HOME_CRUMB = { label: '홈', to: '/home' };
4	const SECTION_CRUMBS = [
5	    { prefix: '/domain', label: '도메인' },
6	    { prefix: '/word', label: '단어' },
7	    { prefix: '/forbidden', label: '금칙어' },
8	    { prefix: '/import', label: '데이터 가져오기' },
9	];
10	
11	const resolveBreadcrumbLabel = (match) => {
12	    const breadcrumb = match.handle?.breadcrumb;
13	
14	    if (typeof breadcrumb === 'function') {
15	        const result = breadcrumb({
16	            params: match.params,
17	            pathname: match.pathname,
18	            id: match.id,
19	        });
20	
21	        if (typeof result === 'string') {
22	            return result;
23	        }
24	
25	        return result?.breadcrumb ?? '';
26	    }
27	
28	    return breadcrumb ?? '';
29	};
30	
31	export const Breadcrumbs = () => {
32	    const matches = useMatches();
33	    const { pathname } = useLocation();
34	
35	    const routeCrumbs = matches
36	        .map((match) => {
37	            const label = resolveBreadcrumbLabel(match);
38	            if (!label) {
39	                return null;
40	            }
41	
42	            return {
43	                label,
44	                to: match.pathname || pathname,
45	            };
46	        })
47	        .filter(Boolean);
48	
49	    const crumbs = pathname === '/home' ? [] : [HOME_CRUMB];
50	
51	    const sectionCrumb = SECTION_CRUMBS.find(
52	        (item) => pathname === item.prefix || pathname.startsWith(`${item.prefix}/`),
53	    );
54	    if (sectionCrumb && !crumbs.some((item) => item.to === sectionCrumb.prefix)) {
55	        crumbs.push({ label: sectionCrumb.label, to: sectionCrumb.prefix });
56	    }
57	
58	    routeCrumbs.forEach((crumb) => {
59	        const exists = crumbs.some((item) => item.label === crumb.label && item.to === crumb.to);
60	        if (!exists) {
61	            crumbs.push(crumb);
62	        }
63	    });
64	
65	    if (crumbs.length === 0) {
66	        crumbs.push(HOME_CRUMB);
67	    }
68	
69	    return (
70	        <nav aria-label='breadcrumb' className='hidden min-w-0 flex-wrap items-center gap-1 text-sm md:flex'>
71	            {crumbs.map((crumb, index) => {
72	                const isLast = index === crumbs.length - 1;
73	
74	                return (
75	                    <span key={`${crumb.label}-${crumb.to}`} className='flex min-w-0 items-center gap-1'>
76	                        {index > 0 ? <span className='text-muted-foreground'>{'>'}</span> : null}
77	                        {isLast ? (
78	                            <span className='truncate font-medium text-foreground'>{crumb.label}</span>
79	                        ) : (
80	                            <Link className='truncate text-muted-foreground transition hover:text-foreground' to={crumb.to}>
81	                                {crumb.label}
82	                            </Link>
83	                        )}
84	                    </span>
85	                );
86	            })}
87	        </nav>
88	    );
89	};
